// Deterministic port of ce-doc-review's CLEAN-MECHANICAL synthesis brackets.
//
// Pure module: no Workflow/Agent/filesystem dependencies. It is importable by
// `bun test` AND designed to be inlined into the dynamic workflow script (the
// Workflow runtime is self-contained and cannot `import` a sibling file, so
// doc-review-fanout.js prepends this module's function bodies; the single
// trailing `export` line is the only thing stripped on inline).
//
// Faithful to:
//   plugins/compound-engineering/skills/ce-doc-review/references/synthesis-and-presentation.md
//   plugins/compound-engineering/skills/ce-doc-review/references/findings-schema.json
//
// SCOPE — only the two CONTIGUOUS clean-mechanical brackets of the pipeline:
//   mergeFront: 3.1 validate -> 3.2 anchor gate -> 3.3 cross-persona dedup
//   mergeBack:  3.7 route    -> 3.8 sort        -> 3.9 suppress restatements
//               -> protected-artifact drop
// The interleaved middle (3.3b collapse, 3.4 cross-persona promotion, 3.5
// contradictions, 3.5b recommended-action tie-break, 3.5c chains, 3.6
// auto-promotion) is owned by the in-workflow synthesis agent (U2) because its
// steps carry bidirectional data dependencies with deterministic steps and
// cannot be split without inverting pipeline order. This module deliberately
// does NOT implement them.
//
// Where the prose delegates a decision to model judgment, this module makes an
// explicit, test-pinned choice marked [INTERP].

const SEVERITY_RANK = { P0: 3, P1: 2, P2: 1, P3: 0 };
const VALID_SEVERITY = new Set(["P0", "P1", "P2", "P3"]);
const VALID_FINDING_TYPE = new Set(["error", "omission"]);
const VALID_AUTOFIX = new Set(["safe_auto", "gated_auto", "manual"]);
const VALID_ANCHORS = new Set([0, 25, 50, 75, 100]);
// Anchors dropped silently by 3.2 (false positive / unverifiable).
const DROPPED_ANCHORS = new Set([0, 25]);
// 3.5c Step 4: cap dependents rendered per root.
const MAX_DEPENDENTS = 6;
// Protected-artifact directories (synthesis "Protected Artifacts").
const PROTECTED_DIRS = ["docs/brainstorms/", "docs/plans/", "docs/solutions/"];

function normalize(value) {
  return String(value).trim().toLowerCase().replace(/\s+/g, " ");
}

function hasFix(finding) {
  return typeof finding.suggested_fix === "string" && finding.suggested_fix.trim().length > 0;
}

// ---------------------------------------------------------------------------
// mergeFront — 3.1 validate, 3.2 anchor gate, 3.3 cross-persona dedup.
// ---------------------------------------------------------------------------

// 3.1: validate one return's findings against the schema vocabulary. Unlike the
// code-review module, doc-review does NOT remap legacy values — the synthesis
// prose treats the pre-rename `auto` / `present` values as malformed and drops
// them until persona output is regenerated.
function validate(returns) {
  const findings = [];
  const softBuckets = { residual_risks: [], deferred_questions: [] };
  const malformedAgents = new Set();
  let droppedReturns = 0;
  let droppedFindings = 0;
  let order = 0;

  for (const ret of Array.isArray(returns) ? returns : []) {
    if (
      !ret ||
      typeof ret.reviewer !== "string" ||
      !Array.isArray(ret.findings) ||
      !Array.isArray(ret.residual_risks) ||
      !Array.isArray(ret.deferred_questions)
    ) {
      droppedReturns++;
      continue;
    }
    softBuckets.residual_risks.push(...ret.residual_risks);
    softBuckets.deferred_questions.push(...ret.deferred_questions);

    for (const raw of ret.findings) {
      if (
        !raw ||
        typeof raw !== "object" ||
        typeof raw.title !== "string" ||
        !VALID_SEVERITY.has(raw.severity) ||
        typeof raw.section !== "string" ||
        typeof raw.why_it_matters !== "string" ||
        !VALID_FINDING_TYPE.has(raw.finding_type) ||
        !VALID_AUTOFIX.has(raw.autofix_class) ||
        !VALID_ANCHORS.has(raw.confidence) ||
        !Array.isArray(raw.evidence) ||
        raw.evidence.length < 1
      ) {
        droppedFindings++;
        malformedAgents.add(ret.reviewer);
        continue;
      }
      findings.push({
        section: raw.section,
        title: raw.title,
        severity: raw.severity,
        finding_type: raw.finding_type,
        autofix_class: raw.autofix_class,
        confidence: raw.confidence,
        why_it_matters: raw.why_it_matters,
        evidence: [...raw.evidence],
        suggested_fix: typeof raw.suggested_fix === "string" ? raw.suggested_fix : null,
        _reviewer: ret.reviewer,
        _order: order++,
      });
    }
  }
  return {
    findings,
    softBuckets,
    droppedReturns,
    droppedFindings,
    malformedAgents: [...malformedAgents].sort(),
  };
}

// 3.3: merge a fingerprint cluster (same normalize(section)+normalize(title))
// into one finding. [INTERP] The prose says preserve opposing-action pairs for
// 3.5; opposing findings in practice carry DIFFERENT titles (-> different
// fingerprints -> never clustered here -> they reach the synthesis agent as
// distinct same-section findings, where 3.5 resolves the contradiction). So an
// identical-fingerprint cluster is treated as the same concern and merged.
function mergeCluster(members) {
  const reviewers = [...new Set(members.map((m) => m._reviewer))].sort();
  // Representative = highest severity, then highest anchor, then first by order.
  const rep = [...members].sort(
    (a, b) =>
      SEVERITY_RANK[b.severity] - SEVERITY_RANK[a.severity] ||
      b.confidence - a.confidence ||
      a._order - b._order,
  )[0];

  const severity = members.reduce(
    (acc, m) => (SEVERITY_RANK[m.severity] > SEVERITY_RANK[acc] ? m.severity : acc),
    "P3",
  );
  // 3.3 keeps the highest confidence anchor. NO cross-persona promotion here —
  // that is 3.4, owned by the synthesis agent.
  const confidence = Math.max(...members.map((m) => m.confidence));

  // [INTERP] autofix_class on merge: the prose does not define a merge rule, so
  // keep the most conservative (more judgment / less silent apply):
  // manual > gated_auto > safe_auto. The agent's 3.6 may still promote it.
  const autofix_class = members
    .map((m) => m.autofix_class)
    .reduce((a, b) => (AUTOFIX_CONSERVATISM[b] > AUTOFIX_CONSERVATISM[a] ? b : a));

  const evidence = [...new Set(members.flatMap((m) => m.evidence))];
  const suggested_fix =
    (members.find((m) => m._reviewer === rep._reviewer && hasFix(m)) ||
      members.find((m) => hasFix(m)) ||
      {}).suggested_fix ?? null;

  return {
    id: normalize(rep.section) + "|" + normalize(rep.title),
    section: rep.section,
    title: rep.title,
    severity,
    finding_type: rep.finding_type,
    autofix_class,
    confidence,
    why_it_matters: rep.why_it_matters,
    evidence,
    suggested_fix,
    reviewers,
    _order: rep._order,
  };
}

const AUTOFIX_CONSERVATISM = { manual: 2, gated_auto: 1, safe_auto: 0 };

/**
 * Front bracket: validate -> anchor gate -> cross-persona dedup.
 * Returns the deduped finding set the synthesis agent consumes, the soft
 * buckets it must carry through to mergeBack, and the front's coverage counts.
 *
 * @param {Array<{reviewer:string, findings:Array, residual_risks:Array, deferred_questions:Array}>} returns
 */
function mergeFront(returns) {
  const { findings, softBuckets, droppedReturns, droppedFindings, malformedAgents } =
    validate(returns);

  // 3.2: drop anchors 0/25 (counted); keep 50/75/100. The FYI-vs-actionable
  // split is finalized by anchor in mergeBack 3.7 — anchors mutate in the agent
  // (3.3b demote -> 50, 3.4 promote 50 -> 75), so the front must not separate.
  let dropped = 0;
  const gated = findings.filter((f) => {
    if (DROPPED_ANCHORS.has(f.confidence)) {
      dropped++;
      return false;
    }
    return true;
  });

  // 3.3: cluster by normalize(section)+normalize(title), merge each cluster.
  const groups = new Map();
  for (const f of gated) {
    const key = normalize(f.section) + "|" + normalize(f.title);
    if (!groups.has(key)) groups.set(key, []);
    groups.get(key).push(f);
  }
  let dedupMerged = 0;
  const merged = [...groups.keys()].sort().map((key) => {
    const cluster = groups.get(key);
    if (cluster.length > 1) dedupMerged += cluster.length - 1;
    return mergeCluster(cluster);
  });

  return {
    findings: merged,
    residual_risks: softBuckets.residual_risks,
    deferred_questions: softBuckets.deferred_questions,
    coverage: {
      dropped, // 3.2 anchors 0/25
      dropped_returns: droppedReturns,
      dropped_findings: droppedFindings,
      malformed_agents: malformedAgents,
      dedup_merged: dedupMerged,
    },
  };
}

// ---------------------------------------------------------------------------
// mergeBack — 3.7 route, 3.8 sort, 3.9 suppress restatements, protected drop.
// ---------------------------------------------------------------------------

// 3.7: apply the anchor x autofix_class route table. Each (anchor, original
// class) cell is a TERMINAL single-step lookup — demotion is not cascaded.
// safe_auto demotes exactly one step to gated_auto (silent apply is reserved
// for 100 + safe_auto + fix); only a finding whose ORIGINAL class is gated_auto
// and which lacks a fix demotes to manual. Returns the destination bucket name.
function routeBucket(f) {
  if (f.confidence === 50) return "fyi"; // anchor 50 -> FYI regardless of class
  if (f.autofix_class === "safe_auto") {
    if (f.confidence === 100 && hasFix(f)) return "applied"; // silent apply
    return "proposed_fixes"; // 75 + safe_auto, or 100 + safe_auto missing a fix
  }
  if (f.autofix_class === "gated_auto") {
    return hasFix(f) ? "proposed_fixes" : "decisions"; // no fix -> manual
  }
  return "decisions"; // manual (suggested_fix optional)
}

// 3.8: P0->P3, errors before omissions, anchor desc, document order final.
// [INTERP] "document order" uses the stable _order index assigned at first
// appearance in mergeFront (the document is not available to a pure module);
// agent-emitted findings without _order sort last within their tie group. This
// preserves determinism — the parity requirement — even if it is not literal
// section position.
function sortFindings(findings) {
  return [...findings].sort(
    (a, b) =>
      SEVERITY_RANK[b.severity] - SEVERITY_RANK[a.severity] ||
      typeRank(a) - typeRank(b) ||
      b.confidence - a.confidence ||
      orderOf(a) - orderOf(b),
  );
}
function typeRank(f) {
  return f.finding_type === "error" ? 0 : 1; // errors before omissions
}
function orderOf(f) {
  return Number.isFinite(f._order) ? f._order : Number.MAX_SAFE_INTEGER;
}

// Protected-artifact predicate: the fix proposes deleting a file under a
// protected docs dir. [INTERP] clear-cut = a protected path token AND a
// deletion verb in the same suggested_fix; borderline mentions are kept.
const DELETE_VERB = /\b(delete|remove|drop|rm)\b/i;
function recommendsProtectedDeletion(f) {
  if (!hasFix(f)) return false;
  const fix = f.suggested_fix;
  const mentionsProtected = PROTECTED_DIRS.some((d) => fix.includes(d));
  return mentionsProtected && DELETE_VERB.test(fix);
}

// 3.9: a residual/deferred item restates an actionable finding when it shares a
// section with one AND its substance overlaps the finding's title/why_it_matters.
// [INTERP] mechanical substance overlap = >=2 shared significant words (>=4
// chars). "When in doubt, keep" — only obvious restatements drop.
const STOPWORDS = new Set([
  "this",
  "that",
  "with",
  "from",
  "have",
  "will",
  "would",
  "could",
  "should",
  "there",
  "their",
  "which",
  "where",
  "when",
  "what",
  "than",
  "then",
  "into",
  "over",
  "under",
  "about",
  "section",
  "document",
  "finding",
]);
function significantWords(text) {
  return new Set(
    normalize(text)
      .replace(/[^a-z0-9\s]/g, " ")
      .split(/\s+/)
      .filter((w) => w.length >= 4 && !STOPWORDS.has(w)),
  );
}
function overlaps(itemWords, finding) {
  const findingWords = significantWords(finding.title + " " + finding.why_it_matters);
  let shared = 0;
  for (const w of itemWords) if (findingWords.has(w)) shared++;
  return shared >= 2;
}
function suppressRestatements(items, actionable) {
  let restated = 0;
  const kept = items.filter((item) => {
    const itemWords = significantWords(item);
    const isRestatement = actionable.some((f) => overlaps(itemWords, f));
    if (isRestatement) {
      restated++;
      return false;
    }
    return true;
  });
  return { kept, restated };
}

// 3.5c count invariant: coverage and rendering must derive from ONE source of
// truth. The synthesis agent can emit inconsistent annotations (a finding listed
// in a root's `dependents` array but with `depends_on: null`, or a depends_on
// pointing at a finding the protected-artifact drop removed). Reconcile both
// sides from the `depends_on` back-pointers (the dependent's own declaration):
// rebuild each root's `dependents` from who actually points at it, clear dangling
// /self depends_on, and apply the cap so the array and back-pointers agree by
// construction. Mutates the findings in place; returns the coverage counts.
function reconcileChains(findings) {
  const byId = new Map(findings.map((f) => [f.id, f]));
  // Clear depends_on that does not point at another surviving finding.
  for (const f of findings) {
    if (f.depends_on && (f.depends_on === f.id || !byId.has(f.depends_on))) f.depends_on = null;
  }
  // Group dependents by their declared root.
  const back = new Map();
  for (const f of findings) {
    if (!f.depends_on) continue;
    if (!back.has(f.depends_on)) back.set(f.depends_on, []);
    back.get(f.depends_on).push(f);
  }
  // Cap per root (keep top 6 by severity, anchor desc, document order); the
  // overflow lose their link and render independently.
  for (const deps of back.values()) {
    deps.sort(
      (a, b) =>
        SEVERITY_RANK[b.severity] - SEVERITY_RANK[a.severity] ||
        b.confidence - a.confidence ||
        orderOf(a) - orderOf(b),
    );
    for (const extra of deps.slice(MAX_DEPENDENTS)) extra.depends_on = null;
  }
  // Rebuild every finding's dependents array from the (post-cap) back-pointers —
  // the agent's original array is discarded so the two sides cannot drift.
  let roots = 0;
  let dependents = 0;
  for (const f of findings) {
    const live = (back.get(f.id) || []).filter((d) => d.depends_on === f.id);
    f.dependents = live.map((d) => d.id);
    if (f.dependents.length > 0) roots++;
    if (f.depends_on) dependents++;
  }
  return { roots, dependents };
}

/**
 * Back bracket: consumes the synthesis agent's annotated finding set (final
 * anchors, recommended_action, autofix_class, depends_on/dependents already
 * set) plus the soft buckets from mergeFront. Routes, sorts, suppresses
 * restatements, drops protected-artifact deletions, and returns the envelope
 * buckets the headless text output is rendered from.
 *
 * @param {Array<object>} annotated  findings keyed by stable id, post-synthesis
 * @param {{residual_risks:Array<string>, deferred_questions:Array<string>}} softBuckets
 */
function mergeBack(annotated, softBuckets) {
  const surviving = (Array.isArray(annotated) ? annotated : []).filter(
    (f) => !recommendsProtectedDeletion(f),
  );

  // Reconcile depends_on/dependents into one consistent structure BEFORE routing
  // so coverage counts and the rendered nesting cannot drift (3.5c invariant).
  const chains = reconcileChains(surviving);

  const buckets = { applied: [], proposed_fixes: [], decisions: [], fyi: [] };
  for (const f of surviving) buckets[routeBucket(f)].push(f);

  buckets.applied = sortFindings(buckets.applied);
  buckets.proposed_fixes = sortFindings(buckets.proposed_fixes);
  buckets.decisions = sortFindings(buckets.decisions);
  buckets.fyi = sortFindings(buckets.fyi);

  // 3.9 runs against the finalized actionable + FYI set.
  const actionable = [
    ...buckets.applied,
    ...buckets.proposed_fixes,
    ...buckets.decisions,
    ...buckets.fyi,
  ];
  const soft = softBuckets || { residual_risks: [], deferred_questions: [] };
  const residual = suppressRestatements(soft.residual_risks || [], actionable);
  const deferred = suppressRestatements(soft.deferred_questions || [], actionable);

  return {
    applied: buckets.applied,
    proposed_fixes: buckets.proposed_fixes,
    decisions: buckets.decisions,
    fyi: buckets.fyi,
    residual_risks: residual.kept,
    deferred_questions: deferred.kept,
    coverage: {
      restated: residual.restated + deferred.restated,
      chains, // { roots, dependents } reconciled from a single source of truth
    },
  };
}


// Assembly inserts merge-doc-findings.js here, exposing mergeFront(returns) and
// mergeBack(annotated, softBuckets).

// ---- args ------------------------------------------------------------------
// The Workflow runtime may deliver `args` as an object OR a JSON string. Parse
// defensively — a naive `args || {}` keeps the raw string and silently runs
// all-defaults (the documented "empty review" failure mode).
let A = args;
if (typeof A === "string") {
  try {
    A = JSON.parse(A);
  } catch (e) {
    log("args was a non-JSON string; running with defaults: " + (e && e.message ? e.message : String(e)));
    A = {};
  }
}
A = A || {};
const RUN_ID = A.run_id || "unknown-run";
const ARTIFACT_DIR = "/tmp/compound-engineering/ce-doc-review/" + RUN_ID;
const PERSONAS = Array.isArray(A.personas) ? A.personas : [];
const DOCUMENT_PATH = A.document_path || "";
const DOCUMENT_TYPE = A.document_type || "requirements";
const ORIGIN_PATH = A.origin_path || "none";

// Full findings schema (findings-schema.json). Personas return FULL findings —
// why_it_matters + evidence are NOT stripped, because the synthesis agent needs
// them for collapse, contradiction, and chain linking (Key Decision 7). The
// detail stays in the workflow runtime; only the final envelope leaves it.
const FINDINGS_SCHEMA = {
  type: "object",
  required: ["reviewer", "findings", "residual_risks", "deferred_questions"],
  properties: {
    reviewer: { type: "string" },
    findings: {
      type: "array",
      items: {
        type: "object",
        required: [
          "title",
          "severity",
          "section",
          "why_it_matters",
          "finding_type",
          "autofix_class",
          "confidence",
          "evidence",
        ],
        properties: {
          title: { type: "string" },
          severity: { type: "string", enum: ["P0", "P1", "P2", "P3"] },
          section: { type: "string" },
          why_it_matters: { type: "string" },
          finding_type: { type: "string", enum: ["error", "omission"] },
          autofix_class: { type: "string", enum: ["safe_auto", "gated_auto", "manual"] },
          suggested_fix: { type: ["string", "null"] },
          confidence: { type: "integer", enum: [0, 25, 50, 75, 100] },
          evidence: { type: "array", items: { type: "string" }, minItems: 1 },
        },
      },
    },
    residual_risks: { type: "array", items: { type: "string" } },
    deferred_questions: { type: "array", items: { type: "string" } },
  },
};

// Synthesis-agent output schema — array-in (post-mergeFront findings) /
// annotated-array-out, keyed by the stable finding id. This round-trip shape has
// no template precedent (code-review's only second-stage agent returned a 2-field
// verdict per finding); it is specified concretely here.
const SYNTHESIS_SCHEMA = {
  type: "object",
  required: ["findings"],
  properties: {
    findings: {
      type: "array",
      items: {
        type: "object",
        required: ["id", "confidence", "autofix_class", "recommended_action", "depends_on", "dependents"],
        properties: {
          id: { type: "string" },
          confidence: { type: "integer", enum: [0, 25, 50, 75, 100] }, // post-3.3b demote / 3.4 promote
          autofix_class: { type: "string", enum: ["safe_auto", "gated_auto", "manual"] }, // post-3.6
          recommended_action: { type: "string", enum: ["Apply", "Defer", "Skip"] }, // post-3.5b
          suggested_fix: { type: ["string", "null"] },
          depends_on: { type: ["string", "null"] }, // post-3.5c
          dependents: { type: "array", items: { type: "string" } }, // post-3.5c
          variant_count: { type: "integer" }, // post-3.3b: related variants demoted on the kept finding
          // For agent-emitted contradiction-combined findings (3.5), the full
          // display fields are supplied and is_new is set.
          is_new: { type: "boolean" },
          section: { type: "string" },
          title: { type: "string" },
          severity: { type: "string", enum: ["P0", "P1", "P2", "P3"] },
          finding_type: { type: "string", enum: ["error", "omission"] },
          why_it_matters: { type: "string" },
          evidence: { type: "array", items: { type: "string" } },
          reviewers: { type: "array", items: { type: "string" } },
        },
      },
    },
  },
};

// ---- persona prompt --------------------------------------------------------
// Lean by design (mirrors the code-review template): persona identity + domain
// calibration come from the agentType (the persona agent file); the schema
// enforces enum structure. Round-1 only — the empty decision primer means the
// persona runs with no prior-round suppression (R29/R30 are orchestrator-side
// and never fire in single-round headless).
function personaPrompt(p) {
  return [
    "You are a specialist document reviewer. Review the document strictly through your reviewer persona.",
    "",
    "Document type: " + DOCUMENT_TYPE,
    "Document path (Read this file): " + DOCUMENT_PATH,
    "Origin: " + ORIGIN_PATH,
    "",
    "<prior-decisions>",
    "Round 1 — no prior decisions.",
    "</prior-decisions>",
    "",
    "Read the document at the path above and analyze it through your persona. You are",
    "operationally read-only: do not edit the document. Use the anchored confidence",
    "rubric and the false-positive suppression rules from your persona definition;",
    "suppress anything you cannot honestly anchor at 50 or higher.",
    "",
    "Write your FULL analysis (every finding with why_it_matters and evidence) to",
    ARTIFACT_DIR + "/" + p.name + ".json.",
    "Return the FULL findings object matching the schema (keep why_it_matters and",
    "evidence — synthesis needs them). Set reviewer to \"" + p.name + "\".",
    "Return an empty findings array if nothing qualifies.",
  ].join("\n");
}

// ---- synthesis agent -------------------------------------------------------
// One context-isolated call that owns the contiguous interleaved middle of the
// pipeline. The step definitions are inlined (the workflow runtime cannot Read
// the reference file) and are faithful to references/synthesis-and-presentation.md.
function synthesisInput(findings) {
  return findings.map((f) => ({
    id: f.id,
    section: f.section,
    title: f.title,
    severity: f.severity,
    finding_type: f.finding_type,
    autofix_class: f.autofix_class,
    confidence: f.confidence,
    why_it_matters: f.why_it_matters,
    evidence: f.evidence,
    suggested_fix: f.suggested_fix,
    reviewers: f.reviewers,
  }));
}

function synthesisPrompt(findings) {
  return [
    "You are the synthesis stage of a multi-persona document review. The mechanical",
    "front (schema validation, anchor gate, cross-persona dedup) has already run. Your",
    "job is the JUDGMENT middle of the pipeline. Run these steps IN THIS EXACT ORDER —",
    "each depends on the previous; do not reorder:",
    "",
    "3.3b SAME-PERSONA PREMISE COLLAPSE. For each persona, cluster that persona's own",
    "findings that share a root premise (same finding_type, overlapping why_it_matters",
    "concern, fixes all obviated by the same upstream decision). For a cluster of N>=3:",
    "keep the single strongest finding (highest anchor, else most concrete evidence),",
    "set its variant_count to N-1, and demote the other N-1 to confidence 50 (FYI).",
    "Demoted variants do NOT participate in 3.4. Collapse within ONE persona only —",
    "never across personas (cross-persona agreement is the independence signal 3.4 rewards).",
    "",
    "3.4 CROSS-PERSONA AGREEMENT PROMOTION. When 2+ independent personas flagged the",
    "same finding (reviewers array length >= 2), promote its anchor one step: 50->75,",
    "75->100. 100 stays. Skip findings demoted in 3.3b.",
    "",
    "3.5 RESOLVE CONTRADICTIONS. When personas disagree on the same section (one says",
    "cut/keep, impossible/essential), emit a NEW combined finding (set is_new:true, a",
    "fresh id, finding_type:error, autofix_class:manual) presenting both sides as a",
    "tradeoff — not a verdict. Same-issue agreement (no disagreement) is already merged;",
    "do not emit a contradiction for it.",
    "",
    "3.5b RECOMMENDED-ACTION TIE-BREAK. Every finding gets exactly one recommended_action.",
    "Scan contributing personas' implied actions in this order, most conservative first —",
    "Skip > Defer > Apply — first match wins. Persona-to-action: safe_auto/gated_auto =>",
    "Apply; manual with a concrete recommended fix => Apply; manual tradeoff/scope question",
    "with no recommended resolution => Defer; low-confidence/suppression-eligible or",
    "'keep as-is' in a contradiction => Skip. If all silent: suggested_fix present => Apply,",
    "absent => Defer. INVARIANT: if the winner is Apply but the finding has no suggested_fix",
    "after 3.6, downgrade to Defer.",
    "",
    "3.5c PREMISE-DEPENDENCY CHAIN LINKING. Identify ROOTS: a finding is a root candidate",
    "only when ALL hold — severity P0 or P1; autofix_class manual; it challenges a",
    "FOUNDATIONAL premise (is X justified / premise unsupported / do-nothing baseline not",
    "evaluated / is the approach right); and its section is framing-level (Summary, Problem",
    "Frame, Overview, Why, Motivation, Goals) OR it questions whether a named component",
    "should exist. Elevate ALL matching roots. For each root, find DEPENDENTS among the",
    "remaining findings: the dependent targets the same component the root challenges, and",
    "its concern would DISSOLVE if the root's premise is rejected. INDEPENDENCE SAFEGUARD —",
    "do NOT link a finding that stands on its own (operational obligations like rollback,",
    "error handling, test coverage; evidence-grounded codebase facts; any safe_auto). When",
    "uncertain, do NOT link. Annotate depends_on (root id) on each dependent and dependents",
    "(array of dependent ids) on each root. A dependent links to at most one root. Cap",
    "dependents at 6 per root (keep top 6 by severity, then anchor desc, then document order).",
    "Linking is annotative only — do not re-route or change anchors here.",
    "",
    "3.6 PROMOTE AUTO-ELIGIBLE FINDINGS. Scan manual findings for promotion to gated_auto",
    "(codebase-pattern-resolved with a concrete cited reference; factually incorrect behavior;",
    "missing standard security/reliability control with an established fix; framework-native-API",
    "substitution) or safe_auto (mechanically-implied completeness with exactly one correct",
    "addition). Do NOT promote scope/priority changes where the author may have weighed hidden",
    "tradeoffs. STRAWMAN SAFEGUARD: if a safe_auto names dismissed alternatives that are",
    "actually plausible, downgrade to gated_auto.",
    "",
    "Return the SAME findings keyed by id, each annotated with its final confidence (post-3.3b/3.4),",
    "autofix_class (post-3.6), recommended_action (post-3.5b), depends_on/dependents (post-3.5c),",
    "variant_count (post-3.3b), and suggested_fix. Include any new contradiction findings with",
    "is_new:true and full display fields (section, title, severity, finding_type, why_it_matters,",
    "evidence, reviewers). Do not drop input findings — every input id must appear in the output.",
    "",
    "Findings (JSON):",
    JSON.stringify(synthesisInput(findings), null, 2),
  ].join("\n");
}

// Re-associate the agent's annotations back onto the front findings by id, and
// append any new contradiction findings. Returns the annotated set mergeBack
// consumes. Used both for the happy path and (with an identity annotator) for
// the degraded fallback when the synthesis agent fails.
function applyAnnotations(frontFindings, synthFindings) {
  const annById = new Map();
  for (const a of Array.isArray(synthFindings) ? synthFindings : []) {
    if (a && typeof a.id === "string") annById.set(a.id, a);
  }
  const frontIds = new Set(frontFindings.map((f) => f.id));
  const out = frontFindings.map((f) => {
    const a = annById.get(f.id);
    if (!a) return { ...f, recommended_action: defaultAction(f), depends_on: null, dependents: [], variant_count: 0 };
    return {
      ...f,
      confidence: VALID_OK(a.confidence) ? a.confidence : f.confidence,
      autofix_class: a.autofix_class || f.autofix_class,
      suggested_fix: a.suggested_fix !== undefined ? a.suggested_fix : f.suggested_fix,
      recommended_action: a.recommended_action || defaultAction(f),
      depends_on: typeof a.depends_on === "string" ? a.depends_on : null,
      dependents: Array.isArray(a.dependents) ? a.dependents : [],
      variant_count: Number.isInteger(a.variant_count) ? a.variant_count : 0,
    };
  });
  // Agent-emitted contradiction findings (ids not present in the front set).
  let order = frontFindings.length;
  for (const a of Array.isArray(synthFindings) ? synthFindings : []) {
    if (!a || typeof a.id !== "string" || frontIds.has(a.id)) continue;
    out.push({
      id: a.id,
      section: a.section || "",
      title: a.title || "",
      severity: a.severity || "P2",
      finding_type: a.finding_type || "error",
      autofix_class: a.autofix_class || "manual",
      confidence: VALID_OK(a.confidence) ? a.confidence : 75,
      why_it_matters: a.why_it_matters || "",
      evidence: Array.isArray(a.evidence) ? a.evidence : [],
      suggested_fix: a.suggested_fix ?? null,
      reviewers: Array.isArray(a.reviewers) ? a.reviewers : [],
      recommended_action: a.recommended_action || "Defer",
      depends_on: typeof a.depends_on === "string" ? a.depends_on : null,
      dependents: Array.isArray(a.dependents) ? a.dependents : [],
      variant_count: 0,
      _order: order++,
    });
  }
  return out;
}
function VALID_OK(c) {
  return c === 0 || c === 25 || c === 50 || c === 75 || c === 100;
}
function defaultAction(f) {
  return f.suggested_fix && String(f.suggested_fix).trim() ? "Apply" : "Defer";
}

// ---- fan-out ---------------------------------------------------------------
phase("Fan-out");

const structured = await parallel(
  PERSONAS.map((p) => () =>
    agent(personaPrompt(p), {
      label: "review:" + p.name,
      phase: "Fan-out",
      agentType: p.agentType,
      schema: FINDINGS_SCHEMA,
      ...(p.model ? { model: p.model } : {}),
    })
      .then((r) => (r ? { ...r, reviewer: r.reviewer || p.name } : null))
      .catch((e) => {
        // Surface dispatch/runtime failures — a swallowed agentType-resolution
        // error reads as a (wrong) empty review.
        log("persona " + p.name + " (" + p.agentType + ") failed: " + (e && e.message ? e.message : String(e)));
        return null;
      }),
  ),
);

const validReturns = structured.filter(Boolean);
const droppedAgents = PERSONAS.length - validReturns.length;

// ---- mechanical front (3.1-3.3) --------------------------------------------
const front = mergeFront(validReturns);

// ---- synthesis (3.3b-3.6) --------------------------------------------------
phase("Synthesize");

let annotated;
let synthesisFailed = false;
if (front.findings.length === 0) {
  annotated = [];
} else {
  const synth = await agent(synthesisPrompt(front.findings), {
    label: "synthesize",
    phase: "Synthesize",
    schema: SYNTHESIS_SCHEMA,
  })
    .then((r) => r)
    .catch((e) => {
      log("synthesis agent failed: " + (e && e.message ? e.message : String(e)));
      return null;
    });
  if (synth && Array.isArray(synth.findings)) {
    annotated = applyAnnotations(front.findings, synth.findings);
  } else {
    // Degrade rather than throw: route the un-annotated front findings so no
    // finding is lost (no promotion/collapse/chains, deterministic defaults).
    synthesisFailed = true;
    annotated = applyAnnotations(front.findings, []);
  }
}

// ---- mechanical back (3.7-3.9 + protected drop) ----------------------------
phase("Merge");
const back = mergeBack(annotated, {
  residual_risks: front.residual_risks,
  deferred_questions: front.deferred_questions,
});

const status =
  validReturns.length === 0 || droppedAgents > 0 || synthesisFailed ? "degraded" : "complete";

log(
  "Report-only complete: " +
    validReturns.length +
    "/" +
    PERSONAS.length +
    " reviewers, " +
    (back.applied.length + back.proposed_fixes.length + back.decisions.length) +
    " actionable, " +
    back.fyi.length +
    " FYI",
);

return {
  status,
  document_type: DOCUMENT_TYPE,
  reviewers: validReturns.map((r) => r.reviewer),
  // The workflow is REPORT-ONLY: it never mutates the document. fixes_to_apply
  // are the anchor-100 safe_auto fixes the ORCHESTRATOR applies after this returns.
  fixes_to_apply: back.applied,
  proposed_fixes: back.proposed_fixes,
  decisions: back.decisions,
  fyi: back.fyi,
  residual_risks: back.residual_risks,
  deferred_questions: back.deferred_questions,
  coverage: {
    dropped: front.coverage.dropped,
    dropped_returns: front.coverage.dropped_returns,
    dropped_findings: front.coverage.dropped_findings,
    malformed_agents: front.coverage.malformed_agents,
    dedup_merged: front.coverage.dedup_merged,
    dropped_agents: droppedAgents,
    restated: back.coverage.restated,
    chains: back.coverage.chains,
  },
  run_id: RUN_ID,
  artifact_path: ARTIFACT_DIR + "/",
};
